arguments.file_text:
@page "/settings"
@using sv_8b697c1d65304eab87519597123ca566.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h5 class="settings-sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="settings-nav-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5"><div class="spinner-border" role="status"></div></div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfile()
                    break;
                case "notifications":
                    @RenderNotifications()
                    break;
                case "security":
                    @RenderSecurity()
                    break;
                case "appearance":
                    @RenderAppearance()
                    break;
            }
        }
    </div>
</div>

@if (!string.IsNullOrEmpty(_toastMessage))
{
    <div class="settings-toast @(_toastIsError ? "toast-error" : "")">
        @_toastMessage
    </div>
}

@if (_showRevokeConfirm)
{
    <div class="settings-modal-backdrop" @onclick="() => _showRevokeConfirm = false">
        <div class="settings-modal" @onclick:stopPropagation="true">
            <h5>Revoke Session</h5>
            <p>Are you sure you want to revoke the session on <strong>@_revokeTarget?.Device</strong> from <strong>@_revokeTarget?.Location</strong>?</p>
            <div class="d-flex gap-2 justify-content-end">
                <button class="btn btn-secondary btn-sm" @onclick="() => _showRevokeConfirm = false">Cancel</button>
                <button class="btn btn-danger btn-sm" @onclick="ConfirmRevokeSession">Revoke</button>
            </div>
        </div>
    </div>
}

@code {
    // ── State ──
    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    // Toast
    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // Profile
    private UserProfile? _savedProfile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    // Notifications
    private bool _emailNotif;
    private bool _pushNotif;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    // Security
    private SecuritySettings? _security;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _twoFactorEnabled;
    private bool _showRevokeConfirm;
    private ActiveSession? _revokeTarget;

    // Appearance
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] Themes = ["Light", "Dark", "System"];
    private static readonly string[] FontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Portuguese"];

    private record SectionDef(string Key, string Label, string Icon);
    private static readonly SectionDef[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        await LoadAllData();
        _loading = false;
    }

    private async Task LoadAllData()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        // Profile
        _savedProfile = profileTask.Result;
        ApplyProfileToForm(_savedProfile);

        // Notifications
        var notif = notifTask.Result;
        _emailNotif = notif.EmailNotifications;
        _pushNotif = notif.PushNotifications;
        _weeklyDigest = notif.WeeklyDigest;
        _allChannels = InMemorySettingsService.GetAllChannels();
        _mutedChannels = [.. notif.MutedChannels];

        // Security
        _security = securityTask.Result;
        _twoFactorEnabled = _security.TwoFactorEnabled;

        // Appearance
        var appearance = appearanceTask.Result;
        _theme = appearance.Theme;
        _fontSize = appearance.FontSize;
        _language = appearance.Language;
        _compactMode = appearance.CompactMode;
    }

    // ── Profile ──

    private void ApplyProfileToForm(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
        _avatarUrl = p.AvatarUrl;
    }

    private async Task SaveProfile()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
            ApplyProfileToForm(_savedProfile);
    }

    private RenderFragment RenderProfile() => __builder =>
    {
        <h3 class="settings-section-title">Profile</h3>

        <div class="profile-layout">
            <div class="profile-avatar-area">
                <div class="avatar-preview">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">👤</div>
                    }
                </div>
                <div class="form-group mt-2">
                    <label class="form-label form-label-sm">Avatar URL</label>
                    <input type="url" class="form-control form-control-sm" @bind="_avatarUrl" />
                </div>
            </div>

            <div class="profile-fields">
                <div class="form-group">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="form-group">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="form-group">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
        </div>

        <div class="settings-actions">
            <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
            <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
        </div>
    };

    // ── Notifications ──

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(_emailNotif, _pushNotif, _weeklyDigest, [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved!");
    }

    private RenderFragment RenderNotifications() => __builder =>
    {
        <h3 class="settings-section-title">Notifications</h3>

        <div class="settings-card">
            <h6>General</h6>
            <div class="toggle-row">
                <label>Email Notifications</label>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" @bind="_emailNotif" />
                </div>
            </div>
            <div class="toggle-row">
                <label>Push Notifications</label>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" @bind="_pushNotif" />
                </div>
            </div>
            <div class="toggle-row">
                <label>Weekly Digest</label>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" @bind="_weeklyDigest" />
                </div>
            </div>
        </div>

        <div class="settings-card mt-3">
            <h6>Muted Channels</h6>
            @foreach (var channel in _allChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check">
                    <input class="form-check-input darker-border-checkbox" type="checkbox"
                           id="@($"ch-{channel}")" checked="@isMuted"
                           @onchange="e => ToggleMutedChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                </div>
            }
        </div>

        <div class="settings-actions">
            <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
        </div>
    };

    // ── Security ──

    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            await ShowToast("Please fill in all password fields.", isError: true);
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            await ShowToast("New passwords do not match.", isError: true);
            return;
        }
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changePasswordExpanded = false;
        _security = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Password updated successfully!");
    }

    private void PromptRevokeSession(ActiveSession session)
    {
        _revokeTarget = session;
        _showRevokeConfirm = true;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_revokeTarget is null) return;
        await SettingsService.RevokeSessionAsync(_revokeTarget.Id);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _showRevokeConfirm = false;
        _revokeTarget = null;
        await ShowToast("Session revoked.");
    }

    private RenderFragment RenderSecurity() => __builder =>
    {
        <h3 class="settings-section-title">Security</h3>

        <!-- Change Password -->
        <div class="settings-card">
            <div class="expandable-header" @onclick="() => _changePasswordExpanded = !_changePasswordExpanded">
                <h6 class="mb-0">Change Password</h6>
                <span class="expand-icon">@(_changePasswordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_changePasswordExpanded)
            {
                <div class="expandable-body">
                    <div class="form-group">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="form-group">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="form-group">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary btn-sm mt-2" @onclick="UpdatePassword">Update Password</button>
                </div>
            }
        </div>

        <!-- Two-Factor -->
        <div class="settings-card mt-3">
            <div class="toggle-row">
                <div>
                    <h6 class="mb-0">Two-Factor Authentication</h6>
                    <small class="text-muted">
                        @if (_twoFactorEnabled)
                        {
                            <span class="badge bg-success">Enabled</span>
                        }
                        else
                        {
                            <span class="badge bg-secondary">Disabled</span>
                        }
                    </small>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
                </div>
            </div>
            @if (_security?.LastPasswordChange is not null)
            {
                <small class="text-muted d-block mt-2">Last password change: @_security.LastPasswordChange.Value.ToString("MMM dd, yyyy")</small>
            }
        </div>

        <!-- Active Sessions -->
        <div class="settings-card mt-3">
            <h6>Active Sessions</h6>
            @if (_security?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-sm table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _security.Sessions)
                            {
                                var isCurrentSession = session == _security.Sessions[0];
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (isCurrentSession)
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                        else
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => PromptRevokeSession(session)">Revoke</button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted mb-0">No active sessions.</p>
            }
        </div>
    };

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    // ── Appearance ──

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved!");
    }

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private string PreviewBackground => _theme switch
    {
        "Dark" => "#1e1e1e",
        _ => "#ffffff"
    };

    private string PreviewTextColor => _theme switch
    {
        "Dark" => "#d4d4d4",
        _ => "#212529"
    };

    private RenderFragment RenderAppearance() => __builder =>
    {
        <h3 class="settings-section-title">Appearance</h3>

        <div class="settings-card">
            <h6>Theme</h6>
            <div class="d-flex gap-3">
                @foreach (var t in Themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="@($"theme-{t}")"
                               value="@t" checked="@(_theme == t)"
                               @onchange="() => _theme = t" />
                        <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                    </div>
                }
            </div>
        </div>

        <div class="settings-card mt-3">
            <h6>Font Size</h6>
            <div class="d-flex gap-3">
                @foreach (var fs in FontSizes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{fs}")"
                               value="@fs" checked="@(_fontSize == fs)"
                               @onchange="() => _fontSize = fs" />
                        <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
                    </div>
                }
            </div>
        </div>

        <div class="settings-card mt-3">
            <h6>Language</h6>
            <select class="form-select" @bind="_language">
                @foreach (var lang in Languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <div class="settings-card mt-3">
            <div class="toggle-row">
                <label>Compact Mode</label>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" @bind="_compactMode" />
                </div>
            </div>
        </div>

        <!-- Live Preview -->
        <div class="settings-card mt-3">
            <h6>Preview</h6>
            <div class="appearance-preview"
                 style="background:@PreviewBackground; color:@PreviewTextColor; font-size:@PreviewFontSize; padding: @(_compactMode ? "0.5rem" : "1rem"); line-height: @(_compactMode ? "1.3" : "1.6");">
                <strong>Dashboard Preview</strong>
                <p class="mb-1">This is how your content will look with the selected settings.</p>
                <p class="mb-0"><small>Theme: @_theme · Font: @_fontSize · Language: @_language · Compact: @(_compactMode ? "On" : "Off")</small></p>
            </div>
        </div>

        <div class="settings-actions">
            <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
        </div>
    };

    // ── Toast ──

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _toastMessage = null;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }
}

.settings-dashboard {
    display: flex;
    gap: 2rem;
    min-height: 70vh;
}

/* ── Sidebar ── */

.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1rem 0;
}

.settings-sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: 0.9rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.settings-nav {
    list-style: none;
    margin: 0;
    padding: 0;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.6rem 1.25rem;
    cursor: pointer;
    font-size: 0.95rem;
    color: #495057;
    transition: background 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.settings-nav-item:hover {
